"use strict";(self.webpackChunkheiman_wiki_public=self.webpackChunkheiman_wiki_public||[]).push([["5975"],{1662(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"welcome","metadata":{"permalink":"/heiman-wiki-public/tr/blog/welcome","source":"@site/i18n/tr/docusaurus-plugin-content-blog/2021-08-26-welcome/index.mdx","title":"Heiman Teknoloji Wiki\'ye Ho\u015F Geldiniz","description":"Heiman Teknoloji Wiki\'ye ho\u015F geldiniz! Bu, \xfcr\xfcn dok\xfcmantasyonu, teknik \xe7\xf6z\xfcmler, sekt\xf6r haberleri ve \u015Firket g\xfcncellemelerini bir araya getiren resmi bilgi taban\u0131d\u0131r.","date":"2021-08-26T00:00:00.000Z","tags":[{"inline":false,"label":"Heiman Teknoloji","permalink":"/heiman-wiki-public/tr/blog/tags/heiman","description":"Heiman Teknoloji haberleri ve g\xfcncellemeleri"}],"readingTime":0.59,"hasTruncateMarker":true,"authors":[{"name":"Heiman Teknoloji","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/tr/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"welcome","title":"Heiman Teknoloji Wiki\'ye Ho\u015F Geldiniz","authors":["heiman"],"tags":["heiman"]},"unlisted":false,"nextItem":{"title":"Heiman Matter Ak\u0131ll\u0131 Duman Alarm\u0131 Resmi Olarak Piyasaya S\xfcr\xfcld\xfc","permalink":"/heiman-wiki-public/tr/blog/mdx-blog-post"}},"content":"Heiman Teknoloji Wiki\'ye ho\u015F geldiniz! Bu, \xfcr\xfcn dok\xfcmantasyonu, teknik \xe7\xf6z\xfcmler, sekt\xf6r haberleri ve \u015Firket g\xfcncellemelerini bir araya getiren resmi bilgi taban\u0131d\u0131r.\\n\\n{/* truncate */}\\n\\n## Bu Site Hakk\u0131nda\\n\\nHeiman Teknoloji Wiki, i\u015F ortaklar\u0131na, geli\u015Ftiricilere ve m\xfc\u015Fterilere tek duraktan teknik kaynak sa\u011Flamaya adanm\u0131\u015Ft\u0131r:\\n\\n- **\xdcr\xfcnler** \u2014 Ak\u0131ll\u0131 Yang\u0131n G\xfcvenli\u011Fi, Ak\u0131ll\u0131 Gaz G\xfcvenli\u011Fi, Ak\u0131ll\u0131 Ya\u015Fl\u0131 Bak\u0131m\u0131, Ak\u0131ll\u0131 Sens\xf6rler\\n- **\xc7\xf6z\xfcmler** \u2014 Sekt\xf6r d\xfczeyinde ak\u0131ll\u0131 g\xfcvenlik \xe7\xf6z\xfcmleri\\n- **Teknik Dok\xfcmanlar** \u2014 API entegrasyon k\u0131lavuzlar\u0131, SDK kullan\u0131m\u0131, kurulum k\u0131lavuzlar\u0131\\n- **Sekt\xf6r \u0130\xe7g\xf6r\xfcleri** \u2014 Ak\u0131ll\u0131 g\xfcvenlik trendleri ve politika yorumlar\u0131\\n\\n## H\u0131zl\u0131 Gezinme\\n\\n- [\xdcr\xfcnler ve \xc7\xf6z\xfcmler](/docs/tutorial-basics/create-a-page) sayfas\u0131n\u0131 inceleyin\\n- Heiman\'\u0131n hikayesini \xf6\u011Frenmek i\xe7in [Hakk\u0131m\u0131zda](/docs/intro) sayfas\u0131n\u0131 okuyun\\n- [Heiman Resmi Sitesini](https://www.heiman.com.cn) ziyaret edin\\n\\nHerhangi bir sorunuz i\xe7in \xe7a\u011Fr\u0131 hatt\u0131m\u0131z\u0131 **400-8959-500** aray\u0131n veya \xe7evrimi\xe7i deste\u011Fe ba\u015Fvurun."},{"id":"mdx-blog-post","metadata":{"permalink":"/heiman-wiki-public/tr/blog/mdx-blog-post","source":"@site/i18n/tr/docusaurus-plugin-content-blog/2021-08-01-mdx-blog-post.mdx","title":"Heiman Matter Ak\u0131ll\u0131 Duman Alarm\u0131 Resmi Olarak Piyasaya S\xfcr\xfcld\xfc","description":"Heiman Teknoloji\'nin yeni nesil Matter protokol\xfc ak\u0131ll\u0131 duman alarm\u0131 HS1SA-M resmi olarak piyasaya s\xfcr\xfcld\xfc \u2014 Matter 1.2 sertifikas\u0131 alan sekt\xf6rdeki ilk duman alarmlar\u0131ndan biridir.","date":"2021-08-01T00:00:00.000Z","tags":[{"inline":false,"label":"Matter","permalink":"/heiman-wiki-public/tr/blog/tags/matter","description":"Matter protokol\xfc ile ilgili i\xe7erikler"},{"inline":false,"label":"Ak\u0131ll\u0131 Yang\u0131n G\xfcvenli\u011Fi","permalink":"/heiman-wiki-public/tr/blog/tags/smart-fire","description":"Ak\u0131ll\u0131 yang\u0131n g\xfcvenli\u011Fi \xfcr\xfcnleri ve \xe7\xf6z\xfcmleri"}],"readingTime":0.65,"hasTruncateMarker":true,"authors":[{"name":"Heiman Teknoloji","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/tr/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"mdx-blog-post","title":"Heiman Matter Ak\u0131ll\u0131 Duman Alarm\u0131 Resmi Olarak Piyasaya S\xfcr\xfcld\xfc","authors":["heiman"],"tags":["matter","smart-fire"]},"unlisted":false,"prevItem":{"title":"Heiman Teknoloji Wiki\'ye Ho\u015F Geldiniz","permalink":"/heiman-wiki-public/tr/blog/welcome"},"nextItem":{"title":"Heiman Teknoloji Kilometre Ta\u015Flar\u0131","permalink":"/heiman-wiki-public/tr/blog/long-blog-post"}},"content":"Heiman Teknoloji\'nin yeni nesil Matter protokol\xfc ak\u0131ll\u0131 duman alarm\u0131 HS1SA-M resmi olarak piyasaya s\xfcr\xfcld\xfc \u2014 Matter 1.2 sertifikas\u0131 alan sekt\xf6rdeki ilk duman alarmlar\u0131ndan biridir.\\n\\n{/* truncate */}\\n\\n:::tip\\n\\nHS1SA-M, Apple HomeKit, Amazon Alexa, Google Home ve Samsung SmartThings \u2014 d\xf6rt b\xfcy\xfck ak\u0131ll\u0131 ev ekosistemini destekler.\\n\\n:::\\n\\n## Temel \xd6zellikler\\n\\n- **Matter 1.2 Sertifikal\u0131** \u2014 \xc7apraz marka, \xe7apraz ekosistem birlikte \xe7al\u0131\u015Fabilirli\u011Fi\\n- **Fotoelektrik Duman Alg\u0131lama** \u2014 \xc7e\u015Fitli yang\u0131n duman t\xfcrlerine h\u0131zl\u0131 tepki\\n- **Sesli Alarm** \u2014 Birden \xe7ok dil se\xe7ene\u011Fi, net tehlike uyar\u0131lar\u0131\\n- **Kendi Kendine Test Fonksiyonu** \u2014 Normal \xe7al\u0131\u015Fmay\u0131 sa\u011Flamak i\xe7in d\xfczenli kendi kendine kontroller\\n- **Uzaktan Bildirim** \u2014 Telefon uygulaman\u0131za ger\xe7ek zamanl\u0131 an\u0131nda bildirimler\\n\\n## Uyumluluk\\n\\nHS1SA-M, ba\u015Fl\u0131ca ak\u0131ll\u0131 ev platformlar\u0131yla sorunsuz bir \u015Fekilde entegre olur ve ek bir a\u011F ge\xe7idi gerektirmez \u2014 her \u015Feyi do\u011Frudan telefonunuzdan y\xf6netin.\\n\\nDaha fazla bilgi i\xe7in [\xdcr\xfcnler](/docs/tutorial-basics/create-a-page) sayfas\u0131n\u0131 ziyaret edin."},{"id":"long-blog-post","metadata":{"permalink":"/heiman-wiki-public/tr/blog/long-blog-post","source":"@site/i18n/tr/docusaurus-plugin-content-blog/2019-05-29-long-blog-post.mdx","title":"Heiman Teknoloji Kilometre Ta\u015Flar\u0131","description":"2005 y\u0131l\u0131nda kurulu\u015Fundan bu yana, Heiman Teknoloji 20 y\u0131l\u0131 a\u015Fk\u0131n bir yolculuk ge\xe7irdi. Bu makale Heiman\'\u0131n \xf6nemli kilometre ta\u015Flar\u0131n\u0131 g\xf6zden ge\xe7irmektedir.","date":"2019-05-29T00:00:00.000Z","tags":[{"inline":false,"label":"Heiman Teknoloji","permalink":"/heiman-wiki-public/tr/blog/tags/heiman","description":"Heiman Teknoloji haberleri ve g\xfcncellemeleri"}],"readingTime":1.08,"hasTruncateMarker":true,"authors":[{"name":"Heiman Teknoloji","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/tr/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"long-blog-post","title":"Heiman Teknoloji Kilometre Ta\u015Flar\u0131","authors":["heiman"],"tags":["heiman"]},"unlisted":false,"prevItem":{"title":"Heiman Matter Ak\u0131ll\u0131 Duman Alarm\u0131 Resmi Olarak Piyasaya S\xfcr\xfcld\xfc","permalink":"/heiman-wiki-public/tr/blog/mdx-blog-post"},"nextItem":{"title":"Heinan Teknoloji Ulusal \\"K\xfc\xe7\xfck Dev\\" Kurulu\u015Fu Olarak Tan\u0131nd\u0131","permalink":"/heiman-wiki-public/tr/blog/first-blog-post"}},"content":"2005 y\u0131l\u0131nda kurulu\u015Fundan bu yana, Heiman Teknoloji 20 y\u0131l\u0131 a\u015Fk\u0131n bir yolculuk ge\xe7irdi. Bu makale Heiman\'\u0131n \xf6nemli kilometre ta\u015Flar\u0131n\u0131 g\xf6zden ge\xe7irmektedir.\\n\\n{/* truncate */}\\n\\n## 2005 - \u015Eirket Kurulu\u015Fu\\n\\nShenzhen Heiman Technology Co., Ltd. resmen kuruldu ve g\xfcvenlik sens\xf6r\xfc alan\u0131na girdi.\\n\\n## 2006 - Uluslararas\u0131 Ba\u015Flang\u0131\xe7\\n\\nBirden fazla \xfcr\xfcn AB CE sertifikas\u0131 ald\u0131 ve China Mobile ile ortakl\u0131k kurdu.\\n\\n## 2011 - Uluslararas\u0131 Sertifikasyon At\u0131l\u0131m\u0131\\n\\nBirden fazla \xfcr\xfcn AB EN54-7 ve EN14604 sertifikalar\u0131n\u0131 alarak uluslararas\u0131 kalite standartlar\u0131na ula\u015Ft\u0131.\\n\\n## 2012 - Ak\u0131ll\u0131 Ev D\xf6n\xfc\u015F\xfcm\xfc\\n\\nAk\u0131ll\u0131 ev projesi tamamen ba\u015Flat\u0131ld\u0131 ve Heiman\'\u0131 ak\u0131ll\u0131 ev \xfcr\xfcnlerinin Ar-Ge, \xfcretim ve sat\u0131\u015F\u0131nda uzmanla\u015Fm\u0131\u015F bir \u015Firkete d\xf6n\xfc\u015Ft\xfcrd\xfc.\\n\\n## 2017 - B\xfcy\xfck At\u0131l\u0131mlar\\n\\n- \xc7in\'in ilk NB-IoT duman alarm\u0131n\u0131 geli\u015Ftirdi\\n- 2 Red Dot Tasar\u0131m \xd6d\xfcl\xfc kazand\u0131\\n- MFi sertifikas\u0131n\u0131 ge\xe7erek Apple \xfcreticisi olarak nitelendirildi\\n\\n## 2020 - Sermaye Deste\u011Fi\\n\\nShenzhen Y\xfcksek Teknoloji Yat\u0131r\u0131m Grubu ile Series A finansman\u0131n\u0131 tamamlad\u0131, \\"Guangdong Eyaleti \xd6zel ve Yeni KOB\u0130\\" olarak tan\u0131nd\u0131.\\n\\n## 2022 - Ulusal Tan\u0131nma\\n\\nUlusal \xd6zel ve Yeni \\"K\xfc\xe7\xfck Dev\\" Kurulu\u015Fu olarak tan\u0131nd\u0131. K1 serisi Red Dot Tasar\u0131m \xd6d\xfcl\xfc kazand\u0131.\\n\\n## 2023 - Uluslararas\u0131 Standartlar Liderli\u011Fi\\n\\nHeiman test laboratuvar\u0131 resmen CNAS sertifikas\u0131 ald\u0131. Duman alarmlar\u0131 ve CO alarmlar\u0131, Matter 1.2 sertifikas\u0131n\u0131 alan ilk \xfcr\xfcnler aras\u0131nda yer ald\u0131.\\n\\n## 2024 - G\xfcn\xfcm\xfcz\\n\\n\u0130novasyona devam ederek, Ak\u0131ll\u0131 Yang\u0131n G\xfcvenli\u011Fi, Ak\u0131ll\u0131 Gaz G\xfcvenli\u011Fi, Ak\u0131ll\u0131 Ya\u015Fl\u0131 Bak\u0131m\u0131 ve Ak\u0131ll\u0131 Sens\xf6rler alanlar\u0131na olan ba\u011Fl\u0131l\u0131\u011F\u0131n\u0131 derinle\u015Ftirerek d\xfcnya \xe7ap\u0131nda 100\'den fazla \xfclkedeki m\xfc\u015Fterilere kaliteli \xfcr\xfcn ve hizmet sunmaktad\u0131r."},{"id":"first-blog-post","metadata":{"permalink":"/heiman-wiki-public/tr/blog/first-blog-post","source":"@site/i18n/tr/docusaurus-plugin-content-blog/2019-05-28-first-blog-post.mdx","title":"Heinan Teknoloji Ulusal \\"K\xfc\xe7\xfck Dev\\" Kurulu\u015Fu Olarak Tan\u0131nd\u0131","description":"2022 y\u0131l\u0131nda Heiman Teknoloji, ak\u0131ll\u0131 sens\xf6r alan\u0131ndaki derin teknik birikimi ve inovasyonu nedeniyle resmen Ulusal \xd6zel ve Yeni \\"K\xfc\xe7\xfck Dev\\" Kurulu\u015Fu olarak tan\u0131nd\u0131.","date":"2019-05-28T00:00:00.000Z","tags":[{"inline":false,"label":"Heiman Teknoloji","permalink":"/heiman-wiki-public/tr/blog/tags/heiman","description":"Heiman Teknoloji haberleri ve g\xfcncellemeleri"}],"readingTime":0.41,"hasTruncateMarker":true,"authors":[{"name":"Heiman Teknoloji","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/tr/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"first-blog-post","title":"Heinan Teknoloji Ulusal \\"K\xfc\xe7\xfck Dev\\" Kurulu\u015Fu Olarak Tan\u0131nd\u0131","authors":["heiman"],"tags":["heiman"]},"unlisted":false,"prevItem":{"title":"Heiman Teknoloji Kilometre Ta\u015Flar\u0131","permalink":"/heiman-wiki-public/tr/blog/long-blog-post"}},"content":"2022 y\u0131l\u0131nda Heiman Teknoloji, ak\u0131ll\u0131 sens\xf6r alan\u0131ndaki derin teknik birikimi ve inovasyonu nedeniyle resmen Ulusal \xd6zel ve Yeni \\"K\xfc\xe7\xfck Dev\\" Kurulu\u015Fu olarak tan\u0131nd\u0131.\\n\\n{/* truncate */}\\n\\nBu ulusal d\xfczeydeki takdir, Heiman\'\u0131n uzmanla\u015Fma, incelik, farkl\u0131la\u015Fma ve inovasyon konular\u0131ndaki m\xfckemmelli\u011Fini onaylamaktad\u0131r. Heiman, Ak\u0131ll\u0131 Yang\u0131n G\xfcvenli\u011Fi, Ak\u0131ll\u0131 Gaz G\xfcvenli\u011Fi, Ak\u0131ll\u0131 Ya\u015Fl\u0131 Bak\u0131m\u0131 ve Ak\u0131ll\u0131 Sens\xf6rler alanlar\u0131ndaki \xe7al\u0131\u015Fmalar\u0131n\u0131 derinle\u015Ftirmeye ve m\xfc\u015Fterilere s\xfcrekli olarak y\xfcksek kaliteli \xfcr\xfcnler ve hizmetler sunmaya devam edecektir.\\n\\nHeiman daha \xf6nce Ulusal Y\xfcksek Teknoloji Kurulu\u015Fu ve Guangdong Eyaleti \xd6zel ve Yeni KOB\u0130 olarak da tan\u0131nm\u0131\u015Ft\u0131."}]}}')}}]);